  const ayahs: AyahProps[] = [
    { ayahId: 67, surahNumber: 2, pageNumber: 10, isComplete: true, continuesFromPrev: true, textData: "۰ﻟ﮲ هُوَ أَدْنۭيٰ بِاﻟ﮲ هُوَ خَيْر٘ؐ 'هْبِطُواْ مِصْراً فَإِنَّ لَكُم مَّا سَأَلْتُمْؐ وَضُرۣبَــتْ عَلَيْهِمُ ۴لذِّلَّةُ وَالْمَسْكَنَةُ وَبَآءُو بِغَضَــبٍ مِّنَ ۰للَّهِؐ ذَ؛لِكَ بِأَنَّهُمْ كَانُواْ يَكْفُرُونَ بِـَٔايَــٰــتِ ۱للَّهِ وَيَقْتُلُونَ ۰لنَّبِيٓــٕﯧنَ بِغَيْرۣ ۱لْحَقﱢّؐ ذَ؛لِكَ بِمَا عَصَواْ وَّكَانُواْ يَعْتَدُونَؐ" },
    { ayahId: 68, surahNumber: 2, pageNumber: 10, isComplete: true, continuesFromPrev: false, textData: "إِنَّ ۰لذِينَ ءَامَنُواْ وَالذِينَ هَادُواْ وَالنَّصَـٰرۭيٰ وَالصَّـٰبِينَ مَنَ ۯمَنَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ وَعَمِلَ صَـٰڤِحاً فَلَهُمُ; أَجْرُهُمْ عِندَ رَبِّهِمْ وَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ" },
    { ayahId: 69, surahNumber: 2, pageNumber: 10, isComplete: true, continuesFromPrev: false, textData: "وَإِذَ اَخَذْنَا مِيثَـــٰقَكُمْ وَرَفَعْنَا فَوْقَكُمُ ۴لطُّورَؐ خُذُواْ مَآ ءَاتَيْنَـٰكُم بِقُوَّةٍ وَاذْكُرُواْ مَا فِيهِ لَعَلَّكُمْ تَتَّقُونَؐ" },
    { ayahId: 70, surahNumber: 2, pageNumber: 10, isComplete: true, continuesFromPrev: false, textData: "ثُمَّ تَوَلَّيْتُم مِّنۢ بَعْدِ ذَ؛لِكَؐ فَلَوْلاَ فَضْلُ ۴للَّهِ عَلَيْكُمْ وَرَحْمَتُهُ„ لَكُنتُم مِّنَ ۰لْخَــٰسِرۣينَؐ" },
    { ayahId: 71, surahNumber: 2, pageNumber: 10, isComplete: true, continuesFromPrev: false, textData: "وَلَقَدْ عَلِمْتُمُ ۴لذِينَ \"عْتَدَوْاْ مِنكُمْ فِى ۱لسَّبْــتِ فَقُلْنَا لَهُمْ كُونُواْ قِرَدَةٗ خَـٰسِـِٕينَؐ" },
    { ayahId: 72, surahNumber: 2, pageNumber: 10, isComplete: true, continuesFromPrev: false, textData: "فَجَعَلْنَـٰهَا نَكَـٰلًا لِّمَا بَيْنَ يَدَيْهَا وَمَا خَلْفَهَا وَمَوْعِظَةً لِّلْمُتَّقِينَؐ ®" },
    { ayahId: 73, surahNumber: 2, pageNumber: 10, isComplete: true, continuesFromPrev: false, textData: "وَإِذْ قَالَ مُوسۭيٰ لِقَوْمِهِ“ إِنَّ ۰للَّهَ يَامُرُكُمُ; أَن تَذْبَحُواْ بَقَرَةًؐ قَـالُوٓاْ أَتَتَّخِذُنَا هُزُؤاًؐ قَالَ أَعُوذُ بِاللَّهِ أَنَ اَكُونَ مِنَ ۰لْجَــٰهِلِينَؐ" }
  ];

